//
// Regression coverage for fix #2: even when back-to-back progress ticks
// occur with no interval sleep, the loop must yield a macrotask so that
// external timers / HTTP handlers aren't starved. The original code
// between progress ticks only touched microtasks, which meant a stream
// of synchronously-resolving awaits could starve macrotask handlers
// (the actual Oculus-unreachable-while-daemon-burns-CPU symptom).

describe('crawl-continual — event-loop starvation guard', () => {
  afterEach(() => clearGuild());

  it('yields a macrotask between progress ticks so external timers can fire', async () => {
    // Schedule a setTimeout(0) BEFORE the handler runs. Inside each crawl
    // call, record whether the timer has fired yet. Without the setImmediate
    // yield, microtasks drain across all progress ticks before the timer's
    // macrotask runs — so `timerFiredAtCall` is never populated inside the
    // loop body. With the yield, the timer fires after the first tick or
    // two.
    const CALLS = 50;
    let callCount = 0;
    let timerFired = false;
    const timerFiredAtCall: number[] = [];

    setTimeout(() => { timerFired = true; }, 0);

    setGuild(makeGuild(async () => {
      if (timerFired) timerFiredAtCall.push(callCount);
      callCount++;
      return callCount < CALLS ? SPAWNED : null;
    }));

    await crawlContinualTool.handler({ maxIdleCycles: 1, pollIntervalMs: 0 });

    assert.ok(
      timerFiredAtCall.length > 0,
      'external setTimeout(0) must fire while the loop is running — starvation regression',
    );
    assert.ok(
      timerFiredAtCall[0]! < 10,
      `timer should fire within the first few ticks; observed first at call ${timerFiredAtCall[0]} of ${CALLS}`,
    );
  });
});

